"""convert LO surface u,v to *.mat, and used for LCS extraction"""from lo_tools import Lfun, zfun, zrfunimport numpy as npimport xarray as xrfrom scipy.io import savematfrom time import timeimport sysfrom pyproj import Projgtagex = 'cas6_v0_live'gridname, tag, ex_name = gtagex.split('_')# get the dict LdirLdir = Lfun.Lstart(gridname=gridname, tag=tag, ex_name=ex_name)Ldir['date_string'] = '2022.08.01'fid=3his = 'ocean_his_000'+str(fid)+'.nc'fn=Ldir['roms_out']/Ldir['gtagex']/('f'+Ldir['date_string'])/hisG, S, T = zrfun.get_basic_info(fn)ds = xr.open_dataset(fn)ds.close()u = ds['u'][0,-1,:,:].values  # surface layerv = ds['v'][0,-1,:,:].valueslat_rho = G['lat_rho']lon_rho = G['lon_rho']# (lon, lat) to utm: zone???#myProj = Proj("+proj=utm +zone=40U, +north +ellps=WGS84 +datum=WGS84 +units=m +no_defs")#lon_m, lat_m = myProj(lon_rho, lat_rho)# save to matlab filemdicU = {'U'+str(fid):u}savemat('U_T'+str(fid)+'.mat',mdicU)mdicV = {'V'+str(fid):v}savemat('V_T'+str(fid)+'.mat',mdicV)